#include <stdint.h>

/* 1. Designated initializers */
struct color { uint8_t r, g, b; };

void designated_init_demo(void) {
    /* Array: initialize specific indices */
    int lookup[10] = { [0] = -1, [5] = 50, [9] = 100 };
    /* Unspecified elements are zero */
    printf("lookup[5]=%d, lookup[3]=%d\n", lookup[5], lookup[3]); /* 50, 0 */

    /* Struct: initialize by name (order independent) */
    struct color red = { .r = 255, .g = 0, .b = 0 };
    struct color blue = { .b = 255 }; /* r and g are 0 */
    printf("red.r=%d, blue.b=%d\n", red.r, blue.b);
}

/* 2. Variable-Length Array */
void vla_demo(int n) {
    int arr[n]; /* VLA: size determined at runtime */
    for (int i = 0; i < n; i++)
        arr[i] = i * i;
    printf("VLA arr[%d-1] = %d\n", n, arr[n - 1]);
}

/* 3. inline function */
static inline int max(int a, int b) {
    return (a > b) ? a : b;
}

/* 4. _Bool type */
void bool_demo(void) {
    _Bool a = 42;   /* _Bool conversion: any non-zero -> 1 */
    bool  b = true; /* via stdbool.h */
    printf("_Bool of 42 = %d\n", a); /* 1 */
    printf("bool true = %d\n", b);   /* 1 */
}

/* 5. Compound literal */
struct point { int x, y; };
void print_point(const struct point *p) {
    printf("(%d, %d)\n", p->x, p->y);
}

/* 6. restrict keyword */
void add_arrays(int * restrict dst,
                const int * restrict a,
                const int * restrict b,
                int n) {
    /* restrict: compiler assumes dst, a, b don't alias */
    for (int i = 0; i < n; i++)
        dst[i] = a[i] + b[i]; /* can be vectorized */
}

int main(void) {
    designated_init_demo();

    /* 5. Mixed declarations and code (C99) */
    printf("Before declaration\n");
    int late_var = 100; /* C89 would require this at top */
    printf("late_var = %d\n", late_var);

    vla_demo(5);
    printf("max(3,7) = %d\n", max(3, 7));
    bool_demo();

    /* Compound literal: create struct inline */
    print_point(&(struct point){ .x = 10, .y = 20 });

