#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <time.h>

/* Without restrict: compiler assumes a and b might alias */
void add_no_restrict(int *a, const int *b, int n) {
    for (int i = 0; i < n; i++)
        a[i] += b[i]; /* must re-read b[i] after writing a[i] */
}

/* With restrict: compiler knows a and b don't overlap */
void add_restrict(int * restrict a, const int * restrict b, int n) {
    for (int i = 0; i < n; i++)
        a[i] += b[i]; /* can vectorize: SIMD, register caching */
}

/* memcpy vs memmove */
void copy_examples(void) {
    char buf[20] = "Hello, World!";

    /* memcpy: restrict -- undefined if src and dst overlap */
    char dst[20];
    memcpy(dst, buf, 14); /* OK: no overlap */
    printf("memcpy: %s\n", dst);

    /* memmove: handles overlapping regions */
    memmove(buf + 3, buf, 10); /* OK: overlap handled */
    printf("memmove: %s\n", buf);
}

/* Real-world: restrict on function parameters */
void matrix_multiply(float * restrict C,
                     const float * restrict A,
                     const float * restrict B,
                     int n) {
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++) {
            float sum = 0.0f;
            for (int k = 0; k < n; k++)
                sum += A[i * n + k] * B[k * n + j];
            C[i * n + j] = sum;
        }
    /* restrict lets compiler vectorize the inner loop */
}

int main(void) {
    const int N = 1000000;
    int *a = malloc(N * sizeof(int));
    int *b = malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) { a[i] = i; b[i] = i; }

    clock_t start;

    start = clock();
    add_no_restrict(a, b, N);
    printf("No restrict: %.3f ms\n",
           1000.0 * (clock() - start) / CLOCKS_PER_SEC);

    start = clock();
    add_restrict(a, b, N);
    printf("With restrict: %.3f ms\n",
           1000.0 * (clock() - start) / CLOCKS_PER_SEC);

    copy_examples();

    free(a);
    free(b);
    return 0;
}

