int safe_add(int a, int b) {
    if ((b > 0 && a > INT_MAX - b) ||
        (b < 0 && a < INT_MIN - b)) {
        fprintf(stderr, "Integer overflow detected!\n");
        return 0; /* or abort */
    }
    return a + b;
}

