/* Rule 1: Use fixed-width integers */
void portable_integers(void) {
    int32_t x = 42;       /* exactly 32 bits */
    uint64_t big = 1ULL << 40;
    size_t len = 100;     /* correct type for sizes */

    /* Rule 9: Correct format specifiers */
    printf("x = %" PRId32 "\n", x);
    printf("big = %" PRIu64 "\n", big);
