/* Rule 2: Portable serialization (endianness-safe) */
void write_uint32_be(uint8_t *buf, uint32_t val) {
    buf[0] = (val >> 24) & 0xFF;
    buf[1] = (val >> 16) & 0xFF;
    buf[2] = (val >> 8)  & 0xFF;
    buf[3] = val & 0xFF;
}

uint32_t read_uint32_be(const uint8_t *buf) {
    return ((uint32_t)buf[0] << 24) |
           ((uint32_t)buf[1] << 16) |
           ((uint32_t)buf[2] << 8)  |
           (uint32_t)buf[3];
}

/* Rule 3: Safe type punning with memcpy */
uint32_t float_to_bits(float f) {
    uint32_t bits;
    memcpy(&bits, &f, sizeof(bits)); /* safe, portable */
    return bits;
    /* BAD: return *(uint32_t *)&f; -- aliasing violation, alignment */
}

/* Rule 5: Use unsigned char for bytes */
void process_bytes(const unsigned char *data, size_t len) {
    for (size_t i = 0; i < len; i++) {
        /* unsigned char: 0-255, no sign issues */
        printf("%02X ", data[i]);
    }
    printf("\n");
}

/* Rule 8: Platform-specific code behind #ifdef */
void platform_sleep(unsigned int ms) {
#ifdef _WIN32
    /* Sleep(ms); */  /* Windows */
#elif defined(__unix__) || defined(__APPLE__)
    /* usleep(ms * 1000); */ /* POSIX */
#else
    /* Busy wait or error */
    (void)ms;
#endif
}

/* Rule 4: Don't assume struct layout for serialization */
struct message {
    uint8_t  type;
    uint32_t length;
    uint16_t flags;
};

size_t serialize_message(uint8_t *buf, const struct message *msg) {
    size_t offset = 0;
    buf[offset++] = msg->type;
    write_uint32_be(buf + offset, msg->length); offset += 4;
    buf[offset++] = (msg->flags >> 8) & 0xFF;
    buf[offset++] = msg->flags & 0xFF;
    return offset; /* total bytes written */
    /* Do NOT: memcpy(buf, msg, sizeof(*msg)) -- padding/endianness! */
}

