    uint8_t buf[4];
    write_uint32_be(buf, 0x12345678);
    uint32_t val = read_uint32_be(buf);
    printf("Round-trip: 0x%08" PRIX32 "\n", val); /* 0x12345678 */

    /* Safe type punning */
    float f = 3.14f;
    printf("Float bits: 0x%08" PRIX32 "\n", float_to_bits(f));

